        }
      },
      {
        key: "trendingMarkets",
        toolId,
        toolName: "discover_trending_markets",
        args: {
          limit: 20,
          sortBy: "liquidity",
          category: "crypto"
        }
      }
    ]
  });

  const topMarketsResult = batch.results.find((entry) => entry.key === "topMarkets");
  const trendingResult = batch.results.find((entry) => entry.key === "trendingMarkets");

  const topMarkets =
    topMarketsResult && topMarketsResult.status === "fulfilled"
      ? topMarketsResult.value
      : null;

  const trendingMarkets =
    trendingResult && trendingResult.status === "fulfilled"
      ? trendingResult.value
      : null;

  const liveMarkets = Array.isArray(topMarkets?.markets) ? topMarkets.markets : [];
  const trendingCandidates = Array.isArray(trendingMarkets?.trendingMarkets)
    ? trendingMarkets.trendingMarkets
    : [];

  const candidates = [...liveMarkets, ...trendingCandidates].filter(
    (m) => m && typeof m === "object" && m.conditionId && m.url
  );

  const ranked = pickTopSemanticCandidates({
    target: "live highest-liquidity crypto market on Polymarket right now",
    candidates,
    requiredTerms: ["crypto", "liquidity", "live"],
    avoidTerms: ["resolved", "ended"],
    limit: 1
  });

  const best = Array.isArray(ranked) ? ranked[0] : null;

  if (!best || !best.conditionId) {
    return {
      missingData: "Could not identify a live highest-liquidity crypto market from discovery results.",
      attemptedBranches: {
        topMarkets: topMarkets ? "fulfilled" : "rejected",
        trendingMarkets: trendingMarkets ? "fulfilled" : "rejected"
      },
      readBatchSummary: batch.summary
    };
  }

