    toolId,
    toolName: "check_market_efficiency",
    args: {
      conditionId: best.conditionId
    }
  });

  const outcomes = Array.isArray(efficiency?.outcomes) ? efficiency.outcomes : [];
  const trueProbs = efficiency?.trueProbabilitiesPercent || efficiency?.trueProbabilities || {};

  const yesOutcome = outcomes.find((o) => String(o?.name || "").toUpperCase() === "YES");
  const noOutcome = outcomes.find((o) => String(o?.name || "").toUpperCase() === "NO");

  return {
    market: efficiency?.market || best.title || null,
    conditionId: efficiency?.conditionId || best.conditionId,
    liquiditySelection: {
      title: best.title || null,
      url: best.url || null,
      liquidity: best.liquidity ?? null,
      volume24h: best.volume24h ?? null,
      currentPrice: best.currentPrice ?? null
    },
    vig: efficiency?.marketEfficiency?.vig,
    vigBps: efficiency?.marketEfficiency?.vigBps,
    isExploitable: efficiency?.marketEfficiency?.efficiency === "exploitable",
    marketEfficiency: efficiency?.marketEfficiency?.efficiency,
    trueProbabilitiesAdjusted: {
      YES: trueProbs?.YES ?? yesOutcome?.impliedProbabilityPercent ?? null,
      NO: trueProbs?.NO ?? noOutcome?.impliedProbabilityPercent ?? null
    },
    fetchedAt: efficiency?.fetchedAt,
    readBatchSummary: batch.summary
  };
}

